const b = $input.first().json.body || $input.first().json;
const spa_id = String(b.spa_id || b.id || '');
if (!spa_id) throw new Error('spa_id obrigatório');
return [{ json: {
  spa_id,
  end_coleta:  b['ufCrm276_1758913732']  || b.end_coleta  || '',
  end_entrega: b['ufCrm276_1758913724'] || b.end_entrega || '',
  tel_coleta:  b['ufCrm276_1758913712']  || b.tel_coleta  || '',
  tel_dest:    b['ufCrm276_1758913684']    || b.tel_dest    || '',
  nome_dest:   b['ufCrm276_1758913742']   || b.nome_dest   || '',
  referencia:  b['ufCrm276_1758913748']  || b.referencia  || '',
  veiculo:     (b['ufCrm276_1764346660'] || ['120767'])[0]   || '120767',
  category_id: b.categoryId         || 730,
} }];

const r0 = $('🌍 Geo Coleta').first().json;
const r1 = $('🌍 Geo Entrega').first().json;
const g0 = r0.results?.[0]?.geometry?.location;
const g1 = r1.results?.[0]?.geometry?.location;
if (!g0) throw new Error('Geocode coleta falhou: ' + JSON.stringify(r0).slice(0,200));
if (!g1) throw new Error('Geocode entrega falhou: ' + JSON.stringify(r1).slice(0,200));
const p = $('📥 Parse').first().json;
// Mapeamento vehicle_id → serviceType
const SVC = {'120767':'MOTORCYCLE','121120':'MPV','666':'VAN','120768':'TRUCK550'};
const payload = {
  serviceType: SVC[p.veiculo] || 'MOTORCYCLE',
  language: 'pt_BR',
  stops: [
    { coordinates:{lat:String(g0.lat),lng:String(g0.lng)}, address:p.end_coleta,
      phone:{displayNumber:p.tel_coleta,countryCode:'+55'} },
    { coordinates:{lat:String(g1.lat),lng:String(g1.lng)}, address:p.end_entrega,
      phone:{displayNumber:p.tel_dest,countryCode:'+55'},
      ...(p.nome_dest ? {poc:p.nome_dest} : {}) }
  ],
  requesterContact:{name:'Promo Brindes',phone:{displayNumber:'1146375517',countryCode:'+55'}},
  specialRequests:[], isRouteOptimized:false
};
return [{ json:{
  spa_id:p.spa_id, category_id:p.category_id,
  http_method:'POST', http_path:'/v3/quotations',
  http_body:JSON.stringify(payload)
}}];

const crypto = require('crypto');
const ts  = Date.now().toString();
const method  = $json.http_method || 'POST';
const path    = $json.http_path;
const bodyStr = $json.http_body || '';
const raw = ts + '\r\n' + method + '\r\n' + path + '\r\n\r\n' + bodyStr;
const sig = crypto.createHmac('sha256', 'sk_prod_v30Ci06vXqPeizCg6e461VZEymmFzMDAXZQwTm3NdYcwyLaS8nxrQEX0JKcp0mAM').update(raw).digest('hex');
return [{ json: { ...$json,
  _auth: 'hmac pk_prod_d38621223012b9ec71d0634589126e3b:' + ts + ':' + sig,
  _ts: ts
}}];

const q = $('🚀 POST Quotation').first().json;
const d = $('📐 Build Payload').first().json;
if (!q.quotationId) throw new Error('Sem quotationId: ' + JSON.stringify(q).slice(0,200));
const stops = q.stops || [];
const total  = parseInt(q.priceBreakdown?.total || '0');
const taxas  = parseInt(q.priceBreakdown?.specialRequests || '0');
const dist   = q.distance?.value ? ((q.distance.value/1000).toFixed(1)+' km') : '';
const tempo  = q.duration?.value ? (Math.round(q.duration.value/60)+' mins') : '';
return [{ json:{
  spa_id: d.spa_id, category_id: d.category_id,
  quotation_id: q.quotationId,
  stop_coleta:  stops[0]?.stopId || '',
  stop_entrega: stops[1]?.stopId || '',
  b24_fields: {
    'ufCrm276_1758655595': q.quotationId,
    'ufCrm276_1758654848':  stops[0]?.stopId || '',
    'ufCrm276_1758654830': stops[1]?.stopId || '',
    'ufCrm276_1758654032':  (total/100).toFixed(2)+'|BRL',
    'ufCrm276_1759402004059':    (taxas/100).toFixed(2)+'|BRL',
    'ufCrm276_1759098131243':    dist,
    'ufCrm276_1759098064876':    tempo,
  }
} }];

const d = $input.first().json;
const token = $env.B24_TOKEN;
const url = 'https://promobrindes.bitrix24.com.br/rest/1/'+token+'/crm.item.update';
const body = {entityTypeId:1690,id:parseInt(d.spa_id),fields:d.b24_fields};
return [{ json:{ _url:url, _body:JSON.stringify(body) } }];
